    "inlineSchema": "generator client {\n  provider     = \"prisma-client\"\n  output       = \"../src/generated/prisma\"\n  moduleFormat = \"cjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ==========================================\n// 5. PESSOAL E CUSTÓDIA\n// ==========================================\n\nmodel User {\n  id           String    @id @default(uuid())\n  email        String    @unique\n  password     String\n  name         String?\n  role         Role      @default(USER)\n  departamento String?\n  ativos       Ativo[]\n  sessions     Session[]\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n}\n\nmodel Session {\n  id           String   @id @default(uuid())\n  refreshToken String\n  userId       String\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userAgent    String?\n  ip           String?\n  revoked      Boolean  @default(false)\n  expiresAt    DateTime\n  createdAt    DateTime @default(now())\n}\n\nenum Role {\n  USER\n  ADMIN\n}\n\n// ==========================================\n// 1. INVENTÁRIO DE HARDWARE\n// ==========================================\n\nmodel Ativo {\n  id             Int       @id @default(autoincrement())\n  tagPatrimonial String    @unique\n  tipo           AtivoTipo @default(LAPTOP)\n  fabricante     String\n  modelo         String\n  numSerie       String    @unique\n  hostname       String?   @unique\n\n  cpu         String?\n  ram         String?\n  discoFisico String?\n  status      AtivoStatus @default(DISPONIVEL)\n  emUso       Boolean     @default(true)\n  dataCompra  DateTime?\n  valor       Decimal?    @db.Decimal(10, 2)\n\n  // Virtualização\n  isVirtualizado Boolean @default(false)\n  hyperVName     String?\n  hostFisicoId   Int?\n  vms            Ativo[] @relation(\"HostVms\")\n  host           Ativo?  @relation(\"HostVms\", fields: [hostFisicoId], references: [id])\n\n  // Relacionamentos - CORRIGIDO: userId deve ser String para bater com User.id\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id])\n\n  configRede ConfigRede?\n  licencas   LicencaAtivo[]\n  aplicacoes Aplicacao[]    @relation(\"AppServidores\")\n\n  observacoes String?  @db.Text\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n}\n\n// ==========================================\n// 2. INVENTÁRIO DE SISTEMAS\n// ==========================================\n\nmodel Aplicacao {\n  id          Int              @id @default(autoincrement())\n  nome        String\n  sigla       String?          @unique\n  descricao   String?          @db.Text\n  categoria   SistemaCategoria @default(OPERACIONAL)\n  criticidade Criticidade      @default(MEDIA)\n\n  businessOwner      String?\n  responsavelTecnico String?\n  contatoFuncional   String?\n  fornecedor         String?\n\n  janelaOperacao    String?\n  backupInfo        String?\n  procedimentoRecup String? @db.Text\n  pontoUnicoFalha   String? @db.Text\n\n  tecnologiaPrincipal String?\n  databaseInfo        String?\n  integracoes         String? @db.Text\n\n  servidores Ativo[] @relation(\"AppServidores\")\n}\n\n// ==========================================\n// 3. INFRAESTRUTURA DE REDE\n// ==========================================\n\nmodel ConfigRede {\n  id            Int     @id @default(autoincrement())\n  ipAddress     String?\n  macAddress    String  @unique\n  vlan          Int?\n  portasUTP     Int?\n  portasFibra   Int?\n  storageConect String?\n  discoStorage  String?\n\n  ativo   Ativo @relation(fields: [ativoId], references: [id])\n  ativoId Int   @unique\n}\n\n// ==========================================\n// 4. SOFTWARE E LICENCIAMENTO\n// ==========================================\n\nmodel Software {\n  id         Int       @id @default(autoincrement())\n  nome       String\n  versao     String?\n  fabricante String\n  licencas   Licenca[]\n}\n\nmodel Licenca {\n  id            Int            @id @default(autoincrement())\n  chaveAtivacao String         @unique\n  dataExpiracao DateTime?\n  software      Software       @relation(fields: [softwareId], references: [id])\n  softwareId    Int\n  instacoes     LicencaAtivo[]\n}\n\nmodel LicencaAtivo {\n  id             Int      @id @default(autoincrement())\n  ativo          Ativo    @relation(fields: [ativoId], references: [id])\n  ativoId        Int\n  licenca        Licenca  @relation(fields: [licencaId], references: [id])\n  licencaId      Int\n  dataInstalacao DateTime @default(now())\n\n  @@unique([ativoId, licencaId])\n}\n\n// --- ENUMS ---\n\nenum AtivoTipo {\n  LAPTOP\n  DESKTOP\n  SERVIDOR_FISICO\n  SERVIDOR_VIRTUAL\n  SWITCH\n  ROTEADOR\n  STORAGE\n  MONITOR\n}\n\nenum AtivoStatus {\n  DISPONIVEL\n  EM_USO\n  MANUTENCAO\n  DESCARTADO\n}\n\nenum SistemaCategoria {\n  ADMINISTRATIVO\n  OPERACIONAL\n}\n\nenum Criticidade {\n  BAIXA\n  MEDIA\n  ALTA\n  CRITICA\n}\n",
